diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..85710b3bf9de 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -867,8 +867,18 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Constant *Op00C;

   // add (sub C1, X), C2 --> sub (add C1, C2), X
-  if (match(Op0, m_Sub(m_Constant(Op00C), m_Value(X))))
+  // Avoid this if the add is used by a shift - preserving this form enables
+  // better codegen for ceiling division patterns like (X + 7) >> 3.
+  if (match(Op0, m_Sub(m_Constant(Op00C), m_Value(X)))) {
+    // Check if this add has a single use that's a shift instruction
+    if (Add.hasOneUse()) {
+      if (auto *User = dyn_cast<Instruction>(*Add.user_begin())) {
+        if (User->isShift() && User->getOperand(0) == &Add)
+          return nullptr;
+      }
+    }
     return BinaryOperator::CreateSub(ConstantExpr::getAdd(Op00C, Op1C), X);
+  }

   Value *Y;

@@ -1699,7 +1709,44 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return &I;
   }

-  // (add A (or A, -A)) --> (and (add A, -1) A)
+  // Fold ceiling division pattern:
+  // add (lshr X, ShiftAmt), (zext (icmp ne (and X, Mask), 0))
+  //   -> lshr (add X, Mask), ShiftAmt
+  // where Mask == (1 << ShiftAmt) - 1
+  {
+    Value *X, *AndVal, *ShiftVal;
+    const APInt *ShiftAmt, *Mask;
+    // Try to match: add (lshr X, ShiftAmt), (zext (icmp ne (and X, Mask), 0))
+    if (match(LHS, m_LShr(m_Value(X), m_APIntAllowPoison(ShiftAmt))) &&
+        LHS->hasOneUse() &&
+        match(RHS, m_ZExt(m_OneUse(m_SpecificICmp(
+                          ICmpInst::ICMP_NE, m_OneUse(m_And(m_Specific(X),
+                                                          m_APIntAllowPoison(Mask))),
+                          m_ZeroInt()))))) {
+      // Check that Mask == (1 << ShiftAmt) - 1
+      if (Mask->countr_one() == ShiftAmt->getZExtValue()) {
+        Value *Added = Builder.CreateAdd(X, ConstantInt::get(X->getType(), *Mask),
+                                         "", /*NUW=*/I.hasNoUnsignedWrap(),
+                                         /*NSW=*/I.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(Added, ConstantInt::get(Ty, *ShiftAmt));
+      }
+    }
+    // Also try with operands swapped
+    if (match(RHS, m_LShr(m_Value(X), m_APIntAllowPoison(ShiftAmt))) &&
+        RHS->hasOneUse() &&
+        match(LHS, m_ZExt(m_OneUse(m_SpecificICmp(
+                          ICmpInst::ICMP_NE, m_OneUse(m_And(m_Specific(X),
+                                                          m_APIntAllowPoison(Mask))),
+                          m_ZeroInt()))))) {
+      // Check that Mask == (1 << ShiftAmt) - 1
+      if (Mask->countr_one() == ShiftAmt->getZExtValue()) {
+        Value *Added = Builder.CreateAdd(X, ConstantInt::get(X->getType(), *Mask),
+                                         "", /*NUW=*/I.hasNoUnsignedWrap(),
+                                         /*NSW=*/I.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(Added, ConstantInt::get(Ty, *ShiftAmt));
+      }
+    }
+  }
   // (add A (or -A, A)) --> (and (add A, -1) A)
   // (add (or A, -A) A) --> (and (add A, -1) A)
   // (add (or -A, A) A) --> (and (add A, -1) A)

